Install:
claude mcp add --transport http server-name https://api.example.com/mcp && claude mcp list

Config:
{
  "mcpServers": {
    "filesystem": {
      "command": "npx",
      "args": ["-y", "@modelcontextprotocol/server-filesystem", "/Users/username/Documents"]
    }
  }
}

